=☑️ *Заявка закрыта*

{{ $('Request status payed').item.json.company_payer }}

*Номер*: {{  $('Request status payed').item.json.id }}
*Проект*: {{ $('Request status payed').item.json.title }}
*Поставщик*: {{ $('Request status payed').item.json.vendor }}
*Категория расхода*: {{ $('Request status payed').item.json.category }}
*Сумма*: {{ Number($('Request status payed').item.json.amount).toLocaleString("ru", {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
    style: "currency", currency: $('Request status payed').item.json.currency
  }) }}
*Тип оплаты*: {{ $('Request status payed').item.json.payment_type }}
*Назначение платежа*: {{ $('Request status payed').item.json.payment_purpose }}
*Описание / зачем*: {{ $('Request status payed').item.json.description }}
*Срочность*: {{ $('Request status payed').item.json.urgency }}
*Заявитель*: {{ $('Request status payed').item.json.requester }}

{{$if(
  $('get attachments').item.json.isEmpty(), 
  "", 
  "📎*Вложения*:\n[" + 
  $('get attachments').item.json.filename.replace(/[_*[\]()~`>#+\-=|{}.!]/g, '\\$&') + 
  "](" + 
  $('get attachments').item.json.file_url
    .replace(/\)/g, '\\)')
    .replace(/\\/g, '\\\\') + 
  ")\n"
)}}
🕒*Дата подачи*: {{ new Date($('Request status payed').item.json.submitted_at).toLocaleString('ru-RU', {  
    hour: '2-digit',
    minute: '2-digit',
    day: '2-digit',
    month: 'long',
    year: 'numeric',

  }) }}

